@Service
public class MfaService {
    private static final int BACKUP_CODES_COUNT = 10;
    private static final int BACKUP_CODE_LENGTH = 16;
    private static final long EXPIRATION_HOURS = 72;
    
    @Autowired
    private UserRepository userRepository;
    
    @Autowired
    private MfaBackupCodeRepository backupCodeRepository;
    
    @Autowired
    private PasswordEncoder passwordEncoder;
    
    public List<String> generateBackupCodes(Long userId) {
        List<String> codes = new ArrayList<>();
        Date expiresAt = new Date(System.currentTimeMillis() + (EXPIRATION_HOURS * 60 * 60 * 1000));
        
        for (int i = 0; i < BACKUP_CODES_COUNT; i++) {
            String code = generateUniqueCode();
            MfaBackupCode backupCode = new MfaBackupCode(userId, code, expiresAt);
            backupCodeRepository.save(backupCode);
            codes.add(code);
        }
        
        return codes;
    }
    
    private String generateUniqueCode() {
        StringBuilder code = new StringBuilder();
        Random random = new Random();
        String chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";
        
        for (int i = 0; i < BACKUP_CODE_LENGTH; i++) {
            code.append(chars.charAt(random.nextInt(chars.length())));
        }
        
        return code.toString();
    }
    
    public boolean validateBackupCode(String code) {
        Optional<MfaBackupCode> backupCodeOptional = backupCodeRepository.findByCodeAndIsUsedFalse(code);
        
        if (backupCodeOptional.isPresent()) {
            MfaBackupCode backupCode = backupCodeOptional.get();
            
            if (backupCode.getExpiresAt().before(new Date())) {
                backupCodeRepository.delete(backupCode);
                return false;
            }
            
            backupCode.setIsUsed(true);
            backupCodeRepository.save(backupCode);
            return true;
        }
        
        return false;
    }
    
    public void enableMfa(Long userId, String secret) {
        User user = userRepository.findById(userId)
            .orElseThrow(() -> new RuntimeException("User not found"));
        user.setMfaEnabled(true);
        user.setMfaSecret(secret);
        userRepository.save(user);
    }
    
    public void disableMfa(Long userId) {
        User user = userRepository.findById(userId)
            .orElseThrow(() -> new RuntimeException("User not found"));
        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        userRepository.save(user);
        
        // Delete existing backup codes
        backupCodeRepository.deleteAll(backupCodeRepository.findByUserId(userId));
    }
    
    public List<String> getActiveBackupCodes(Long userId) {
        return backupCodeRepository.findByUserIdAndIsUsedFalse(userId)
            .stream()
            .map(MfaBackupCode::getCode)
            .collect(ArrayList::new, ArrayList::add, ArrayList::addAll);
    }
}

@RestController
@RequestMapping("/api/mfa")
public class MfaController {
    @Autowired
    private MfaService mfaService;
    
    @Autowired
    private UserRepository userRepository;
    
    @PostMapping("/enable")
    public ResponseEntity<?> enableMfa(@RequestParam Long userId, 
                                      @RequestParam String secret) {
        try {
            mfaService.enableMfa(userId, secret);
            List<String> backupCodes = mfaService.generateBackupCodes(userId);
            return ResponseEntity.ok(backupCodes);
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error enabling MFA: " + e.getMessage());
        }
    }
    
    @PostMapping("/disable")
    public ResponseEntity<?> disableMfa(@RequestParam Long userId) {
        try {
            mfaService.disableMfa(userId);
            return ResponseEntity.ok("MFA disabled successfully");
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error disabling MFA: " + e.getMessage());
        }
    }
    
    @PostMapping("/authenticate")
    public ResponseEntity<?> authenticate(@RequestParam String code) {
        try {
            boolean isValid = mfaService.validateBackupCode(code);
            if (isValid) {
                return ResponseEntity.ok("Authentication successful");
            } else {
                return ResponseEntity.status(401).body("Invalid or expired backup code");
            }
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Authentication error: " + e.getMessage());
        }
    }
    
    @GetMapping("/backup-codes")
    public ResponseEntity<?> getBackupCodes(@RequestParam Long userId) {
        try {
            List<String> codes = mfaService.getActiveBackupCodes(userId);
            return ResponseEntity.ok(codes);
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error retrieving backup codes: " + e.getMessage());
        }
    }
}

